-- Import des cinéastes (généré automatiquement à partir de cineastes.json)
-- À coller et exécuter dans le SQL Editor de Supabase, après avoir créé la table.

ON CONFLICT (nom) DO UPDATE SET
  fbid = EXCLUDED.fbid,
  url_facebook = EXCLUDED.url_facebook,
  duo = EXCLUDED.duo,
  naissance = EXCLUDED.naissance,
  deces = EXCLUDED.deces,
  vivant = EXCLUDED.vivant,
  tops_contributeurs = EXCLUDED.tops_contributeurs;